import { useContext, useState } from 'react';
import { X, Plus, Minus, Send, ShoppingBag, MessageCircle } from 'lucide-react';
import { CartContext } from '../context/CartContext';
import './Cart.css';

export default function Cart({ isOpen, onClose }) {
  const { cartItems, removeFromCart, updateQuantity, getCartTotal } = useContext(CartContext);
  const [showCheckoutForm, setShowCheckoutForm] = useState(false);
  const [orderData, setOrderData] = useState({
    name: '',
    phone: '',
    type: 'Dine-in'
  });

  const subtotal = getCartTotal();
  const gst = subtotal * 0.05;
  const total = subtotal + gst;

  const handleCheckoutSubmit = (e) => {
    e.preventDefault();

    // 1. Save to Local Storage Database for Admin
    const newOrder = {
      id: `ORD-${Math.floor(Math.random() * 10000)}`,
      customer: orderData.name,
      phone: orderData.phone,
      type: orderData.type,
      items: cartItems,
      subtotal,
      gst,
      total,
      time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      timestamp: new Date().toISOString(),
      status: 'Pending'
    };

    const existingOrders = JSON.parse(localStorage.getItem('yummy_orders_db') || '[]');
    localStorage.setItem('yummy_orders_db', JSON.stringify([newOrder, ...existingOrders]));

    // 2. Format WhatsApp Message
    const RestaurantPhone = "919876543210"; // Simulated 
    let message = `*New Order: ${newOrder.id}*\n`;
    message += `Type: ${orderData.type}\n`;
    message += `Customer: ${orderData.name} (${orderData.phone})\n\n`;
    message += `*Items:*\n`;
    
    cartItems.forEach(item => {
      message += `${item.quantity}x ${item.name} - ₹${item.price * item.quantity}\n`;
    });
    
    message += `\nSubtotal: ₹${subtotal}`;
    message += `\nGST (5%): ₹${gst.toFixed(2)}`;
    message += `\n*Total: ₹${total.toFixed(2)}*`;

    const encodedMessage = encodeURIComponent(message);
    const whatsappUrl = `https://wa.me/${RestaurantPhone}?text=${encodedMessage}`;
    
    window.open(whatsappUrl, '_blank');
    
    setShowCheckoutForm(false);
    onClose();
  };

  if (!isOpen) return null;

  return (
    <>
      <div className="cart-backdrop" onClick={onClose}></div>
      <div className="cart-drawer fade-in">
        <div className="cart-header">
          <div className="cart-title">
            <ShoppingBag size={20} />
            <h2>Your Order</h2>
          </div>
          <button className="btn-icon" onClick={onClose}>
            <X size={20} />
          </button>
        </div>

        <div className="cart-body">
          {cartItems.length === 0 ? (
            <div className="cart-empty text-muted">
              <ShoppingBag size={48} opacity={0.2} />
              <p>Your cart is empty.</p>
              <button 
                className="btn-primary mt-4" 
                onClick={onClose}
              >
                Browse Menu
              </button>
            </div>
          ) : (
            <div className="cart-items">
              {cartItems.map(item => (
                <div key={item.id} className="cart-item">
                  <div className="cart-item-info">
                    <h4>{item.name}</h4>
                    <span className="cart-item-price">₹{item.price}</span>
                  </div>
                  <div className="cart-item-controls">
                    <button 
                      className="qty-btn-small" 
                      onClick={() => {
                        if (item.quantity > 1) updateQuantity(item.id, item.quantity - 1);
                        else removeFromCart(item.id);
                      }}
                    >
                      <Minus size={14} />
                    </button>
                    <span>{item.quantity}</span>
                    <button 
                      className="qty-btn-small" 
                      onClick={() => updateQuantity(item.id, item.quantity + 1)}
                    >
                      <Plus size={14} />
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {cartItems.length > 0 && (
          <div className="cart-footer border-top">
            <div className="cart-summary">
              <div className="summary-row">
                <span className="text-muted">Subtotal</span>
                <span>₹{subtotal.toFixed(2)}</span>
              </div>
              <div className="summary-row">
                <span className="text-muted">GST (5%)</span>
                <span>₹{gst.toFixed(2)}</span>
              </div>
              <div className="summary-row total">
                <span>Total</span>
                <span className="text-primary">₹{total.toFixed(2)}</span>
              </div>
            </div>

            {showCheckoutForm ? (
              <div className="checkout-form-container fade-in mt-4">
                <h3 className="mb-2" style={{ fontSize: '1rem' }}>Order Details</h3>
                <form onSubmit={handleCheckoutSubmit} className="checkout-form">
                  <div className="form-group mb-2">
                    <input 
                      type="text" 
                      className="input-base" 
                      placeholder="Your Name" 
                      required 
                      value={orderData.name}
                      onChange={e => setOrderData({...orderData, name: e.target.value})}
                    />
                  </div>
                  <div className="form-group mb-2">
                    <input 
                      type="tel" 
                      className="input-base" 
                      placeholder="Phone Number" 
                      required 
                      value={orderData.phone}
                      onChange={e => setOrderData({...orderData, phone: e.target.value})}
                    />
                  </div>
                  <div className="form-group mb-4">
                    <select 
                      className="input-base" 
                      value={orderData.type}
                      onChange={e => setOrderData({...orderData, type: e.target.value})}
                    >
                      <option value="Dine-in">Dine-in (Table)</option>
                      <option value="Takeaway">Takeaway (Pickup)</option>
                      <option value="Delivery">Delivery</option>
                    </select>
                  </div>
                  <button type="submit" className="btn-success w-full" style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.5rem' }}>
                    <MessageCircle size={18} /> Confirm & Send WhatsApp
                  </button>
                  <button type="button" className="btn-secondary w-full mt-2" onClick={() => setShowCheckoutForm(false)}>
                    Back to Cart
                  </button>
                </form>
              </div>
            ) : (
              <div className="cart-actions mt-4">
                <button 
                  className="btn-success w-full" 
                  style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.5rem' }} 
                  onClick={() => setShowCheckoutForm(true)}
                >
                  Proceed to Checkout
                </button>
              </div>
            )}
          </div>
        )}
      </div>
    </>
  );
}

import { createContext, useContext, useState } from 'react';

const CartContext = createContext();

export function CartProvider({ children }) {
  const [cart, setCart] = useState([]);
  const [isCartOpen, setIsCartOpen] = useState(false);

  const addToCart = (item) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        return prev.map(i => i.id === item.id ? { ...i, qty: i.qty + 1 } : i);
      }
      return [...prev, { ...item, qty: 1 }];
    });
  };

  const removeFromCart = (id) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id, amount) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = item.qty + amount;
        return newQty > 0 ? { ...item, qty: newQty } : item;
      }
      return item;
    }));
  };

  const cartTotal = cart.reduce((total, item) => total + (item.price * item.qty), 0);
  const cartCount = cart.reduce((count, item) => count + item.qty, 0);

  return (
    <CartContext.Provider value={{ 
      cart, 
      addToCart, 
      removeFromCart, 
      updateQuantity, 
      cartTotal, 
      cartCount,
      isCartOpen,
      setIsCartOpen
    }}>
      {children}
    </CartContext.Provider>
  );
}

export function useCart() {
  return useContext(CartContext);
}

